fix:
import java.io.IOException;
import java.io.Writer;
import java.util.HashMap;
import java.util.Map;

/**
 * Unicode-specific implementation of {@link org.apache.commons.lang3.text.translate.NumericEntityUnescaper}.
 */
public final class NumericUnicodeEscaper extends NumericEntityUnescaper {
    /** The sole instance. */
    private static final NumericUnicodeEscaper INSTANCE = new NumericUnicodeEscaper();

    /** Cache of frequent codes. */
    private static final Map<Integer, Character> FREQUENT_CHARS = new HashMap<>();

    /** Maximum size of frequent chars cache. */
    private static final int MAX_CACHE_SIZE = 512;

    static {
        for (int code = 0; code <= 0xFFFF; code++) {
            FREQUENT_CHARS.put(code, (char) code);
        }
    }

    /** Private constructor, use {@link #INSTANCE} instead. */
    private NumericUnicodeEscaper() {}

    @Override
    public Object clone() throws CloneNotSupportedException {
        throw new CloneNotSupportedException("Instance has singleton properties");
    }

    @Override
    public int translate(final CharSequence input, final int index, final Appendable output) throws IOException {
        int codePoint = Character.codePointAt(input, index);
        Character cachedCharacter = FREQUENT_CHARS.get(codePoint);
        if (cachedCharacter != null) {
            output.append(cachedCharacter);
            return index + 1;
        } else if (codePoint >= 0x800 && codePoint < 0x10000) {
            appendAsTwoDigitHex(output, codePoint >> 12 & 0xf);
            appendAsTwoDigitHex(output, codePoint >>  8 & 0xf);
            appendAsTwoDigitHex(output, codePoint >>  4 & 0xf);
            appendAsTwoDigitHex(output, codePoint       & 0xf);
            return index + 2;
        } else {
            throw new UnsupportedOperationException("Code point " + codePoint + " does not map to a supported unicode escape sequence.");
        }
    }

    private static void appendAsTwoDigitHex(Appendable output, int value) throws IOException {
        char highChar  = Character.toChars(value)[0];
        output.append("\\u"+ Integer.toHexString(highChar));
    }
}

issue_description:
Supplementary characters in UTF-16 are those whose code points are above 0xffff, that is, require more than 1 Java char to be encoded, as explained here: http://java.sun.com/developer/technicalArticles/Intl/Supplementary/
Currently, StringEscapeUtils.escapeXML() isn't aware of this coding scheme and treats each char as one character, which is not always right.
A possible solution in class Entities would be:
    public void escape(Writer writer, String str) throws IOException {
        int len = str.length();
        for (int i = 0; i < len; i++) {
            int code = str.codePointAt;
            String entityName = this.entityName(code);
            if (entityName != null) 
{
                writer.write('&');
                writer.write(entityName);
                writer.write(';');
            }
 else if (code > 0x7F) 
{
                    writer.write("&#");
                    writer.write(code);
                    writer.write(';');
            }
 else 
{
                    writer.write((char) code);
            }

            if (code > 0xffff) 
{
                    i++;
            }
        }
    }
Besides fixing escapeXML(), this will also affect HTML escaping functions. I guess that's a good thing, but please remember I have only tested escapeXML().

